-- ============================================================================
-- Quiz Seed: Song of Solomon (Chapters 1–8)
-- 3 kids + 5 teens + 8 adults × 8 chapters = 128 total questions
-- ============================================================================

-- ═══ Song of Solomon Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Song of Solomon', 1, 'kids', 1, 'What is the very first thing the book of Song of Solomon calls itself?', 'The song of songs, which is Solomon''s', 'The proverbs of Solomon the king', 'The psalms of David''s son', 'The wisdom of the king of Israel', 'a', 'Song of Solomon 1:1 — "The song of songs, which is Solomon''s." The book opens by describing itself as the greatest or most excellent of songs.'),
('Song of Solomon', 1, 'kids', 2, 'What does the woman say her beloved''s love is better than?', 'Wine', 'Honey', 'Gold', 'Perfume', 'a', 'Song of Solomon 1:2 — "Let him kiss me with the kisses of his mouth: for thy love is better than wine."'),
('Song of Solomon', 1, 'kids', 3, 'How does the woman describe herself when she speaks to the daughters of Jerusalem?', 'I am black but comely', 'I am young but wise', 'I am poor but faithful', 'I am small but lovely', 'a', 'Song of Solomon 1:5 — "I am black, but comely, O ye daughters of Jerusalem, as the tents of Kedar, as the curtains of Solomon."'),
-- Teens
('Song of Solomon', 1, 'teens', 1, 'What does the woman say her mother''s children were angry at her for?', 'They made her keeper of the vineyards and she had not kept her own vineyard', 'They forced her to work in the fields without rest', 'They refused to let her attend the feast of Solomon', 'They were jealous that Solomon had chosen her above all others', 'a', 'Song of Solomon 1:6 — "My mother''s children were angry with me; they made me the keeper of the vineyards; but mine own vineyard have I not kept."'),
('Song of Solomon', 1, 'teens', 2, 'What question does the woman ask her beloved about where he feeds his flock at noon?', 'Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon', 'Where dost thou lead thy sheep in the heat of the day, O beloved?', 'In what pasture dost thou dwell that I may find thee, O shepherd king?', 'Where shall I seek thee at the noonday, lest I turn aside in sorrow?', 'a', 'Song of Solomon 1:7 — "Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon: for why should I be as one that turneth aside by the flocks of thy companions?"'),
('Song of Solomon', 1, 'teens', 3, 'What two animals'' hair or movement does the beloved compare the woman to in chapter 1?', 'Her hair is like a flock of goats and her eyes are like doves', 'Her cheeks are like a young roe and her lips like a thread of scarlet', 'Her neck is like the tower of David and her step like a young hart', 'Her eyes are as doves and her feet like hinds'' feet on the mountains', 'a', 'Song of Solomon 1:15 — "Behold, thou art fair, my love; behold, thou art fair; thou hast doves'' eyes." And Song of Solomon 4:1 — "thy hair is as a flock of goats that appear from mount Gilead," but the dove imagery first appears in 1:15.'),
('Song of Solomon', 1, 'teens', 4, 'What does the woman compare the beloved to — a tree or plant — in chapter 1?', 'A bundle of myrrh that lies all night between her breasts', 'A cedar of Lebanon that stretches over the mountains', 'An apple tree among the trees of the wood', 'A vine whose fragrance fills the house', 'a', 'Song of Solomon 1:13 — "A bundle of myrrh is my well-beloved unto me; he shall lie all night betwixt my breasts."'),
('Song of Solomon', 1, 'teens', 5, 'What does the woman say about the king''s chambers in chapter 1?', 'The king hath brought me into his chambers and we will be glad and rejoice in thee', 'He led me through the halls of his palace to the great feasting room', 'He opened the doors of his treasure house and showed me all his glory', 'He brought me before his throne and set a crown upon my head', 'a', 'Song of Solomon 1:4 — "The king hath brought me into his chambers: we will be glad and rejoice in thee, we will remember thy love more than wine: the upright love thee."'),
-- Adults
('Song of Solomon', 1, 'adults', 1, 'What is the literary force of the title "Song of Songs" (shir hashirim) and what grammatical construction does it employ?', 'It is a Hebrew superlative construction (X of Xs) meaning the greatest or most excellent song, paralleling "Holy of Holies" and "King of Kings"', 'It indicates the song is a collection of many shorter songs compiled by Solomon', 'It is a dedication formula meaning the song belongs to the collection of songs', 'It is a liturgical heading indicating the song was sung in the temple at festivals', 'a', 'Song of Solomon 1:1 — "The song of songs, which is Solomon''s." The construct form shir hashirim is a Hebrew idiom for the superlative, as in Qodesh Haqqodashim (Holy of Holies, Exodus 26:33) and Melek Melakim (King of Kings, Ezekiel 26:7), meaning this is the supreme song.'),
('Song of Solomon', 1, 'adults', 2, 'What does the woman''s statement "I am black but comely" reveal about the social dynamics she is navigating in the Jerusalem court?', 'She acknowledges her dark complexion from outdoor labour (watching vineyards) which set her apart from the court women, yet asserts her worth and beauty', 'She is confessing spiritual unworthiness before entering the holy city', 'She is describing a skin disease that had been healed, making her comely again', 'She is contrasting her Cushite ancestry with Israelite women as a statement of pride', 'a', 'Song of Solomon 1:5-6 — "I am black, but comely, O ye daughters of Jerusalem...Look not upon me, because I am black, because the sun hath looked upon me; my mother''s children were angry with me; they made me the keeper of the vineyards." Her darkness is explained by exposure to the sun in outdoor labour, not by origin.'),
('Song of Solomon', 1, 'adults', 3, 'What is the significance of the olfactory (smell) imagery in Song of Solomon 1:3, and how does it function in the poem?', 'The name of the beloved is said to be as ointment poured forth, connecting his very identity with sweet fragrance — his reputation and person are inseparably pleasant', 'The ointment imagery is purely descriptive of the perfumes used in the royal court', 'It is a reference to priestly anointing oil, suggesting the beloved is a Levite', 'The fragrance imagery establishes the garden setting that dominates the entire book', 'a', 'Song of Solomon 1:3 — "Because of the savour of thy good ointments thy name is as ointment poured forth, therefore do the virgins love thee." The equation of name (reputation and person) with poured ointment is a rich metaphor: just as perfume fills a room when poured, the beloved''s presence and character pervade and delight all who encounter him.'),
('Song of Solomon', 1, 'adults', 4, 'How do the two animal comparisons in Song of Solomon 1:9 — the woman likened to "a company of horses in Pharaoh''s chariots" — function as praise, and what does this image convey?', 'Egyptian chariot horses were among the most prized and magnificent animals in the ancient world; comparing the woman to them praises her as strikingly beautiful, strong, and arresting in appearance', 'The horse comparison reflects Israel''s dependence on Egyptian military alliance and is a political metaphor', 'The beloved is warning her that her beauty attracts too much attention, like a horse draws eyes', 'The chariot horse image is a negative comparison showing she is unruly and needs discipline', 'a', 'Song of Solomon 1:9 — "I have compared thee, O my love, to a company of horses in Pharaoh''s chariots." Egyptian royal chariot horses were celebrated for their beauty, strength, and ornamentation throughout the ancient Near East. The comparison is unambiguous praise of arresting, majestic beauty.'),
('Song of Solomon', 1, 'adults', 5, 'What does the beloved''s description of the couch as "green" (our bed is green, Song 1:16) contribute to the book''s recurring garden theology?', 'It introduces the outdoor, Eden-like setting where love flourishes — the book consistently images true love as thriving in a garden space that recalls the created order before the Fall', 'It identifies the meeting place as a literal garden rather than a palace', 'It is a colour reference to the fertility of the harvest season during which the poem was composed', 'It contrasts with the stone walls of the palace to show the woman preferred rural simplicity', 'a', 'Song of Solomon 1:16-17 — "Our bed is green. The beams of our house are cedar, and our rafters of fir." The green bed and cedar beams construct a natural dwelling that anticipates the garden imagery of chapters 2, 4, and 6, evoking creation''s original garden and the restoration of pure love.'),
('Song of Solomon', 1, 'adults', 6, 'What literary device is used in Song of Solomon 1:2-4 where the beloved shifts between second person ("let him kiss me") and third person, and what effect does this produce?', 'The shift between third person longing and second person address (thee/thy) mimics the alternating distance and closeness of desire — the beloved speaks about him when absent and to him when present in imagination', 'The grammatical shift is a scribal error introduced when the poem was transcribed from oral tradition', 'It reflects two different speakers — a chorus and the woman — whose voices were later merged', 'The shift is a standard feature of Hebrew love poetry with no particular literary significance', 'a', 'Song of Solomon 1:2-4 — "Let him kiss me" (third person, v.2), then "Draw me, we will run after thee" (second person, v.4). This oscillation between he and thou is a poetic representation of longing — the beloved speaks of the absent lover and then suddenly to him, collapsing the distance in desire.'),
('Song of Solomon', 1, 'adults', 7, 'In what sense do rabbinic and patristic interpreters read Song of Solomon 1:2 — "thy love is better than wine" — allegorically, and what does each tradition identify as the two parties?', 'Rabbinic tradition reads the Beloved as God (or Torah) and the woman as Israel; patristic tradition reads Christ as the Beloved and the Church or the soul as the woman — in both, the verse expresses the superiority of divine love over earthly pleasures', 'Rabbinic interpreters read Solomon as the beloved and a historical Shulamite woman as the bride with no allegorical meaning', 'Patristic interpreters read the verse as a warning against wine but have no identification of the parties', 'Both traditions reject the allegorical reading and treat the book as a purely literary love poem', 'a', 'Song of Solomon 1:2 — "Let him kiss me with the kisses of his mouth: for thy love is better than wine." Rabbi Akiva defended the book''s inclusion in the canon saying "all the Writings are holy but the Song of Songs is the Holy of Holies" (Mishnah Yadaim 3:5), reading it as Israel''s love for God. Origen''s commentary identifies the Bridegroom as the Logos and the bride as the soul/Church.'),
('Song of Solomon', 1, 'adults', 8, 'How does the woman''s self-description in Song of Solomon 1:5-6 subvert conventional ancient Near Eastern beauty standards and what is its theological implication?', 'By explaining her dark skin as the result of labour forced upon her by her brothers, she challenges the court''s aesthetic hierarchy and asserts that her worth is not diminished by social disadvantage — pointing toward a theology of intrinsic dignity', 'She is simply providing a biographical explanation with no subversive or theological dimension', 'She is contrasting herself negatively with the ideal beauty celebrated in the royal court', 'She is appealing to the daughters of Jerusalem to feel sorry for her difficult circumstances', 'a', 'Song of Solomon 1:5-6 — "I am black, but comely...Look not upon me, because I am black, because the sun hath looked upon me; my mother''s children were angry with me." The construction but comely directly challenges the dismissal implied by her complexion. Her beauty is not despite her story but through it — a pattern consistent with Scripture''s repeated elevation of the overlooked.');

-- ═══ Song of Solomon Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Song of Solomon', 2, 'kids', 1, 'What two flowers does the woman call herself in chapter 2?', 'The rose of Sharon and the lily of the valleys', 'The lily of the field and the flower of Carmel', 'The tulip of Zion and the rose of the garden', 'The lily of Galilee and the hyssop of the wall', 'a', 'Song of Solomon 2:1 — "I am the rose of Sharon, and the lily of the valleys."'),
('Song of Solomon', 2, 'kids', 2, 'What does the woman say her beloved''s banner over her was?', 'Love', 'Peace', 'Strength', 'Honour', 'a', 'Song of Solomon 2:4 — "He brought me to the banqueting house, and his banner over me was love."'),
('Song of Solomon', 2, 'kids', 3, 'What small animals does the woman say spoil or ruin the vines?', 'The little foxes', 'The small rabbits', 'The young deer', 'The little sparrows', 'a', 'Song of Solomon 2:15 — "Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes."'),
-- Teens
('Song of Solomon', 2, 'teens', 1, 'What does the woman ask to be given because she is sick with love?', 'Flagons and apples to comfort her', 'Rest and shade to refresh her', 'Wine and song to strengthen her', 'His presence and his voice to revive her', 'a', 'Song of Solomon 2:5 — "Stay me with flagons, comfort me with apples: for I am sick of love."'),
('Song of Solomon', 2, 'teens', 2, 'What does the woman describe happening in nature as she hears the voice of her beloved leaping over the mountains?', 'Winter is past, the rain is over and gone, flowers appear on the earth, and the time of the singing of birds has come', 'The rivers overflow and the trees blossom in the early spring rain', 'The dew falls at morning and the stars appear at evening', 'The harvest fields are ripe and the shepherd leads his flock to water', 'a', 'Song of Solomon 2:11-12 — "For, lo, the winter is past, the rain is over and gone; The flowers appear on the earth; the time of the singing of birds is come."'),
('Song of Solomon', 2, 'teens', 3, 'What animal does the beloved reslikened to as he leaps over the mountains to come to the woman?', 'A roe or young hart', 'A young lion', 'A swift horse', 'A gazelle of the field', 'a', 'Song of Solomon 2:9 — "My beloved is like a roe or a young hart: behold, he standeth behind our wall, he looketh forth at the windows."'),
('Song of Solomon', 2, 'teens', 4, 'What does the woman say her beloved says to her — what does he invite her to do?', 'Rise up, my love, my fair one, and come away', 'Come sit beside me under the apple tree', 'Let us go down to the garden before the heat of the day', 'Arise and follow me to the mountains of spices', 'a', 'Song of Solomon 2:10 — "My beloved spake, and said unto me, Rise up, my love, my fair one, and come away."'),
('Song of Solomon', 2, 'teens', 5, 'What does the woman say about her beloved at the end of chapter 2 using possessive language?', 'My beloved is mine, and I am his: he feedeth among the lilies', 'I am his and he is mine: we are one flesh and one spirit', 'He is mine alone and I shall not seek another', 'My beloved has chosen me above all the daughters of Jerusalem', 'a', 'Song of Solomon 2:16 — "My beloved is mine, and I am his: he feedeth among the lilies."'),
-- Adults
('Song of Solomon', 2, 'adults', 1, 'What is the literary significance of the woman''s self-identification as "the rose of Sharon, and the lily of the valleys" in Song of Solomon 2:1?', 'She uses wildflower imagery to describe herself as common and accessible — Sharon was a broad coastal plain with abundant wildflowers — yet the beloved immediately elevates her above all others in verse 2', 'She is comparing herself to the cultivated garden flowers of the royal palace gardens', 'She is asserting royal status by identifying herself with the emblematic flowers of Israel', 'The flowers are symbols of purity borrowed from the temple imagery of 1 Kings 7', 'a', 'Song of Solomon 2:1-2 — "I am the rose of Sharon, and the lily of the valleys. As the lily among thorns, so is my love among the daughters." She describes herself modestly as a common wildflower; he immediately transforms that self-assessment into superlative praise, saying she outshines all others as a lily outshines thorns.'),
('Song of Solomon', 2, 'adults', 2, 'What is the theological significance of "his banner over me was love" (Song of Solomon 2:4) given the military use of banners (degel) in the Hebrew Bible?', 'A battle banner identified the commanding power under whose authority soldiers fought; here love is declared the ruling power and identity marker of the beloved''s household — an inversion of war imagery to celebrate covenant loyalty', 'The banner is purely decorative and refers to the ornate decorations of Solomon''s feasting hall', 'The banner imagery connects to the tribe of Judah''s lion banner, making this a messianic statement', 'It is a metaphor borrowed from Canaanite festival poetry with no specific Hebrew military resonance', 'a', 'Song of Solomon 2:4 — "He brought me to the banqueting house, and his banner over me was love." In Numbers 1:52 and 2:2-3, every tribe camped under its own banner (degel). To be under a banner is to be claimed and protected by it. Here love (ahavah) is raised as the sovereign principle — the couple''s identifying standard.'),
('Song of Solomon', 2, 'adults', 3, 'What does the "little foxes that spoil the vines" (Song of Solomon 2:15) represent in the literary context of the chapter, and how has it been read allegorically?', 'In context it warns that small destructive forces must be caught before they ruin the tender relationship at its most vulnerable stage (tender grapes = early love); allegorically it has been read as the small sins or distractions that damage the soul''s relationship with God', 'It is a practical agricultural instruction with no figurative meaning in its context', 'The foxes represent rival suitors whom the woman is warning her beloved to drive away', 'It is a proverb about the harvest season that was inserted by a later editor and disrupts the love poem', 'a', 'Song of Solomon 2:15 — "Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes." The verse interrupts the love dialogue to sound a note of vigilance — even small, seemingly harmless things (little foxes) can ruin what is fragile and precious (tender grapes of new love). Origen and Bernard of Clairvaux both read the foxes as the small vices that destroy spiritual devotion.'),
('Song of Solomon', 2, 'adults', 4, 'How does the season description in Song of Solomon 2:11-13 function both poetically and theologically?', 'The passing of winter and the arrival of spring flowers, birdsong, and fruit serve as a cosmic backdrop declaring that love is the animating force of creation''s renewal — nature itself participates in the beloved''s call', 'The season description is a literal calendar marker dating the events of the poem to early spring', 'The winter imagery refers to the woman''s period of separation in her brothers'' service, now ended', 'The spring setting is borrowed from Egyptian love poetry and has no indigenous theological significance', 'a', 'Song of Solomon 2:11-13 — "For, lo, the winter is past, the rain is over and gone; The flowers appear on the earth; the time of the singing of birds is come, and the voice of the turtle is heard in our land; The fig tree putteth forth her green figs." The beloved''s invitation to "rise up and come away" is set against total seasonal renewal — creation awakening mirrors the awakening of love.'),
('Song of Solomon', 2, 'adults', 5, 'What is the structural and relational significance of the mutual possession formula in Song of Solomon 2:16 — "My beloved is mine, and I am his"?', 'It is a covenant formula expressing complete mutual belonging — neither party possesses the other unilaterally; the chiastic structure (my beloved is mine / I am his) enacts equality of belonging', 'It is the woman''s declaration of emotional dependency on the beloved', 'It is a legal formula confirming a marriage contract had been executed', 'The formula is a prayer addressed to God asking Him to confirm the relationship', 'a', 'Song of Solomon 2:16 — "My beloved is mine, and I am his: he feedeth among the lilies." This dodi li wa-ani lo formula recurs in 6:3 and is inverted in 7:10 (I am my beloved''s and his desire is toward me), showing a progression in the woman''s self-understanding from mutual possession to full surrender.'),
('Song of Solomon', 2, 'adults', 6, 'What is the significance of the beloved standing behind the wall and looking through the lattice (Song of Solomon 2:9), and how does it create tension in the poem?', 'The image of the beloved glimpsed through windows and lattice creates erotic and emotional tension — he is present yet separated, visible yet not grasped — a pattern of presence-in-absence that runs through the book', 'It describes Solomon''s palace architecture and gives historical detail about Israelite royal buildings', 'The beloved is hiding from the daughters of Jerusalem who are pursuing him', 'The lattice image is borrowed from temple imagery where God was said to look through the lattice of the heavens', 'a', 'Song of Solomon 2:9 — "Behold, he standeth behind our wall, he looketh forth at the windows, shewing himself through the lattice." The alternation between visible and concealed, near and distant, is a structural motif of the book: the beloved is seen but not yet held, which intensifies the desire expressed throughout.'),
('Song of Solomon', 2, 'adults', 7, 'How does the beloved''s address "O my dove, that art in the clefts of the rock" (Song of Solomon 2:14) function as a portrait of the woman?', 'The dove in the rock clefts is hidden and hard to reach; the beloved calls her to let him see her face and hear her voice, suggesting her shyness or modesty makes her lovelier but also harder to access', 'It is a geographical description placing the woman in the wilderness regions of the Sinai', 'The dove image is a divine title borrowed from Psalm 74:19 and elevates the woman to the status of Israel', 'He is comparing her unfavourably to doves that refuse to fly, calling her to be more bold', 'a', 'Song of Solomon 2:14 — "O my dove, that art in the clefts of the rock, in the secret places of the stairs, let me see thy countenance, let me hear thy voice; for sweet is thy voice, and thy countenance is comely." The dove hidden in rocks is inaccessible and precious; the beloved''s longing to see and hear her face and voice makes her elusiveness itself an element of praise.'),
('Song of Solomon', 2, 'adults', 8, 'What does the charge "I adjure you, O daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please" (Song of Solomon 2:7) reveal about the poem''s understanding of love''s timing?', 'Love has its own natural season and must not be forced or hurried; the adjuration by wild animals (symbols of freedom and natural motion) reinforces that love flowers according to its own organic timing and cannot be manufactured', 'It is a warning to the court women not to physically disturb the sleeping beloved', 'It indicates the relationship is secret and the woman fears exposure before they are formally married', 'The charge is a liturgical formula used to consecrate a sacred space', 'a', 'Song of Solomon 2:7 — "I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please." This refrain recurs in 3:5 and 8:4. The adjuration by wild, free animals rather than by God or the king emphasises the naturalness of love''s timing — it cannot and should not be compelled.');

-- ═══ Song of Solomon Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Song of Solomon', 3, 'kids', 1, 'What does the woman do at night when she cannot find her beloved?', 'She rises and seeks him in the city streets and broad ways', 'She prays to God until morning', 'She sends a message to his house', 'She asks the daughters of Jerusalem to find him', 'a', 'Song of Solomon 3:2 — "I will rise now, and go about the city in the streets, and in the broad ways I will seek him whom my soul loveth."'),
('Song of Solomon', 3, 'kids', 2, 'Who found the woman when she was searching in the city at night?', 'The watchmen that go about the city', 'The servants of Solomon''s house', 'The daughters of Jerusalem', 'The merchants in the marketplace', 'a', 'Song of Solomon 3:3 — "The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?"'),
('Song of Solomon', 3, 'kids', 3, 'How many valiant men surrounded Solomon''s litter or bed?', 'Threescore or sixty', 'Forty', 'One hundred', 'Twelve', 'a', 'Song of Solomon 3:7 — "Behold his bed, which is Solomon''s; threescore valiant men are about it, of the valiant of Israel."'),
-- Teens
('Song of Solomon', 3, 'teens', 1, 'When the woman finally found her beloved after searching the city, what did she do?', 'She held him and would not let him go until she had brought him to her mother''s house', 'She ran to tell the daughters of Jerusalem she had found him', 'She brought him before the king for his blessing', 'She sat with him in the city square until morning', 'a', 'Song of Solomon 3:4 — "It was but a little that I passed from them, but I found him whom my soul loveth: I held him, and would not let him go, until I had brought him into my mother''s house, and into the chamber of her that conceived me."'),
('Song of Solomon', 3, 'teens', 2, 'What do the valiant men around Solomon''s litter each hold, and why?', 'Every man hath his sword upon his thigh because of fear in the night', 'They carry torches to light the royal procession', 'They hold spears to guard against enemies on the road', 'They bear the gifts of the king to present to the bride', 'a', 'Song of Solomon 3:8 — "They all hold swords, being expert in war: every man hath his sword upon his thigh because of fear in the night."'),
('Song of Solomon', 3, 'teens', 3, 'What did King Solomon make the pillars of his litter from?', 'The silver posts, gold bottom, and purple covering were made with love by the daughters of Jerusalem', 'Cedar of Lebanon for the posts, gold for the covering, and purple for the seats', 'He made the pillars of silver, the bottom of gold, the covering of purple, and the midst paved with love by the daughters of Jerusalem', 'Ivory posts with cedar flooring and linen curtains sewn by the virgins of Israel', 'a', 'Song of Solomon 3:10 — "He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem."'),
('Song of Solomon', 3, 'teens', 4, 'What is King Solomon wearing when he comes out of the wilderness on his wedding day?', 'The crown wherewith his mother crowned him on the day of his espousals', 'The royal diadem set with twelve precious stones for the twelve tribes', 'The priestly garments with the breastplate of the high priest', 'A garland of cedar and myrrh plaited by the daughters of Jerusalem', 'a', 'Song of Solomon 3:11 — "Go forth, O ye daughters of Zion, and behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart."'),
('Song of Solomon', 3, 'teens', 5, 'From where does Solomon''s litter come up, described as pillars of smoke perfumed with myrrh and frankincense?', 'The wilderness, like pillars of smoke', 'From the valley of Lebanon with incense burning', 'From the palace gardens in the cool of the day', 'Out of the north with clouds of glory', 'a', 'Song of Solomon 3:6 — "Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all powders of the merchant?"'),
-- Adults
('Song of Solomon', 3, 'adults', 1, 'What is the literary function of the night-search narrative in Song of Solomon 3:1-4, and how does it differ from the parallel search in chapter 5?', 'In chapter 3 the search succeeds immediately and the woman brings the beloved home; in chapter 5 the search ends in injury and failure, suggesting a movement from innocent love to the painful cost of deeper intimacy', 'Both searches are identical and serve only to create suspense before reunion', 'The chapter 3 search is a dream while the chapter 5 search is literal, but both end in reunion', 'The chapter 3 search introduces a new character (the watchmen) who reappear in the wedding procession', 'a', 'Song of Solomon 3:4 — "I found him whom my soul loveth: I held him, and would not let him go." Compare Song of Solomon 5:6-7 — "I sought him, but I found him not...the watchmen found me, they smote me, they wounded me." The structural parallel with contrasting outcomes traces the deepening cost of love.'),
('Song of Solomon', 3, 'adults', 2, 'What does the elaborate description of Solomon''s litter (Song of Solomon 3:9-10) — made of cedar, silver, gold, and purple — contribute to the poem''s theology of love?', 'It shows that earthly royal splendour serves love — the greatest king in Israel lavished his finest craftsmanship on the vehicle of espousals, making love the end to which even royal power and wealth are directed', 'It is a historical record of Solomon''s actual wedding chariot preserved in the poem', 'The litter description interrupts the love poem and belongs to a separate court narrative', 'It contrasts royal ostentation with the natural simplicity of true love, criticising Solomon''s excess', 'a', 'Song of Solomon 3:9-10 — "King Solomon made himself a chariot of the wood of Lebanon. He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem." The climax — "paved with love" — transforms the catalogue of luxury: the floor of all this glory is love itself.'),
('Song of Solomon', 3, 'adults', 3, 'What is the significance of the refrain "I adjure you, O daughters of Jerusalem" (Song of Solomon 3:5) appearing in both chapters 2 and 3?', 'It serves as a structural refrain dividing the poem''s movements and reinforcing the book''s central wisdom: love must not be forced but allowed to unfold in its own time', 'It is the chorus of a liturgical antiphon sung by a women''s choir during the wedding ceremony', 'It marks the points where the poem shifts from the woman''s voice to Solomon''s voice', 'It was inserted by a later editor to frame the two night-search narratives as a unit', 'a', 'Song of Solomon 2:7 and 3:5 — "I charge you, O ye daughters of Jerusalem...that ye stir not up, nor awake my love, till he please." The repetition of this identical refrain creates a structural boundary, the recurring wisdom that love cannot be compelled — a principle the book both teaches and embodies.'),
('Song of Solomon', 3, 'adults', 4, 'How does the image of Solomon''s procession coming out of the wilderness "like pillars of smoke" (Song of Solomon 3:6) resonate with Israel''s Exodus narrative?', 'It echoes the pillar of cloud and fire that led Israel through the wilderness (Exodus 13:21-22), investing the royal wedding with the imagery of divine presence and covenant faithfulness', 'The smoke pillars are from the incense burned by the merchants travelling with Solomon''s caravan', 'It is a weather description — a dust storm raised by the horses of the royal procession', 'The wilderness setting is simply geographical and the smoke imagery has no Exodus resonance', 'a', 'Song of Solomon 3:6 — "Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense?" Exodus 13:21 — "And the LORD went before them by day in a pillar of a cloud, to lead them the way; and by night in a pillar of fire." The same wilderness-and-pillar imagery casts the royal bridal procession in covenantal, even theophanic, colours.'),
('Song of Solomon', 3, 'adults', 5, 'What does the mother''s crowning of Solomon (Song of Solomon 3:11) reveal about the roles of women in covenant blessing in the Hebrew tradition?', 'The mother''s coronation of her son on his wedding day gives women a formal role in covenant transmission — as Bathsheba''s intercession secured Solomon''s throne (1 Kings 1), so the mother''s crown marks the wedding covenant', 'The crowning by the mother is a Canaanite wedding custom absorbed into Israelite practice with no covenant significance', 'It indicates Solomon''s father David had died before the wedding, leaving the mother as the only senior family member', 'The mother''s crown is a literary device to introduce a female speaker in the poem', 'a', 'Song of Solomon 3:11 — "Behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart." The mother''s active role in coronating the groom on his wedding day parallels Proverbs 31:1 (the teaching of Lemuel''s mother) and reflects women''s significant place in blessing and covenant in Israel.'),
('Song of Solomon', 3, 'adults', 6, 'Why does the woman use the phrase "him whom my soul loveth" (Song of Solomon 3:1,2,3,4) four times in the search narrative rather than giving the beloved a name?', 'The fourfold repetition of "him whom my soul loveth" instead of a name creates an intensity of longing that transcends identification — she is not seeking a person so much as her soul''s entire completion', 'The beloved''s name was a royal secret that could not be written in a public poem', 'It is a poetic convention of ancient Hebrew love poetry to avoid personal names in search passages', 'The repetition indicates four separate searches on four consecutive nights', 'a', 'Song of Solomon 3:1-4 — "I sought him whom my soul loveth" (v.1), "I will seek him whom my soul loveth" (v.2), "Saw ye him whom my soul loveth?" (v.3), "I found him whom my soul loveth" (v.4). The fourfold use of the same phrase rather than a name transforms the individual into the object of the soul''s whole desire, giving the search universal resonance.'),
('Song of Solomon', 3, 'adults', 7, 'How does the beloved''s role in chapter 3 — arriving in regal splendour — compare to his earlier portrayal as a leaping roe in chapter 2, and what does the contrast reveal?', 'Chapter 2 presents the beloved in intimate, personal motion (leaping, speaking at the window); chapter 3 presents him in public, royal grandeur (litter, escort, crown). Together they portray love that is both privately tender and publicly honoured', 'The two portrayals are incompatible and suggest the chapters were composed by different authors', 'The roe imagery of chapter 2 was meant to embarrass the king and was later corrected by the procession narrative', 'The contrast is between the woman''s private dream in chapter 2 and the public reality of chapter 3', 'a', 'Song of Solomon 2:8-9 — "Behold, he cometh leaping upon the mountains, skipping upon the hills. My beloved is like a roe or a young hart." Song of Solomon 3:7-8 — "Behold his bed, which is Solomon''s; threescore valiant men are about it...expert in war." The agile roe and the guarded king are two facets of the same beloved — intimate and majestic.'),
('Song of Solomon', 3, 'adults', 8, 'What is the rhetorical purpose of the question "Who is this that cometh out of the wilderness?" (Song of Solomon 3:6), and how does it function in the book''s pattern of questions?', 'The question is posed by admiring onlookers who cannot categorise what they see — love and splendour combined exceed familiar categories; it is one of several "who is this?" questions in the book (Song of Solomon 6:10, 8:5) that frame the beloved and the relationship as something beyond ordinary comparison', 'It is asked by the watchmen who are suspicious of the unidentified procession', 'The question is rhetorical and simply introduces the description of Solomon''s litter that follows', 'It is posed by the woman herself, expressing wonder that her beloved is coming for her', 'a', 'Song of Solomon 3:6 — "Who is this that cometh out of the wilderness like pillars of smoke?" Song of Solomon 6:10 — "Who is she that looketh forth as the morning?" Song of Solomon 8:5 — "Who is this that cometh up from the wilderness?" This pattern of unanswerable "who is this?" questions positions both the beloved and their love as exceeding ordinary definition.');

-- ═══ Song of Solomon Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Song of Solomon', 4, 'kids', 1, 'What does the beloved compare the woman''s eyes to?', 'Doves', 'Stars', 'Pools of water', 'Bright gems', 'a', 'Song of Solomon 4:1 — "Behold, thou art fair, my love; behold, thou art fair; thou hast doves'' eyes within thy locks."'),
('Song of Solomon', 4, 'kids', 2, 'What does the beloved call the woman in chapter 4 — what kind of garden?', 'A garden enclosed', 'A garden of spices', 'An open garden of flowers', 'A garden by still waters', 'a', 'Song of Solomon 4:12 — "A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed."'),
('Song of Solomon', 4, 'kids', 3, 'What does the beloved compare the woman''s hair to in chapter 4?', 'A flock of goats that appear from mount Gilead', 'A cluster of dark grapes on the vine', 'Flowing rivers from the mountains of Lebanon', 'Threads of fine purple silk', 'a', 'Song of Solomon 4:1 — "Thy hair is as a flock of goats that appear from mount Gilead."'),
-- Teens
('Song of Solomon', 4, 'teens', 1, 'What does the beloved compare the woman''s teeth to in chapter 4?', 'A flock of sheep that are even shorn, whereof every one bear twins, and none is barren among them', 'Rows of white ivory polished and smooth', 'White pearls set in coral', 'Sheep washed in milk standing by the river', 'a', 'Song of Solomon 4:2 — "Thy teeth are like a flock of sheep that are even shorn, which came up from the washing; whereof every one bear twins, and none is barren among them."'),
('Song of Solomon', 4, 'teens', 2, 'What four spice trees does the beloved say are found in the woman''s garden?', 'Spikenard, saffron, calamus, and cinnamon', 'Frankincense, myrrh, cedar, and aloes', 'Pomegranates, camphire, spikenard, and henna', 'Cassia, calamus, myrrh, and olive', 'a', 'Song of Solomon 4:14 — "Spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices." The primary named quartet introduced in the catalogue begins with spikenard, saffron, calamus, and cinnamon.'),
('Song of Solomon', 4, 'teens', 3, 'What does the beloved call the woman that suggests she is pure and untouched — what is the fountain?', 'A fountain sealed', 'A fountain of living waters', 'A spring of the morning dew', 'A well of deep waters', 'a', 'Song of Solomon 4:12 — "A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed."'),
('Song of Solomon', 4, 'teens', 4, 'From where does the beloved ask the north and south winds to blow so that the spices of the garden will flow out?', 'He calls upon the north wind to awake and the south wind to come and blow upon his garden', 'He asks the winds of Lebanon to carry the perfume to the daughters of Jerusalem', 'He invites the morning winds from mount Hermon to scatter the fragrance of the vineyard', 'He prays for rain from the north and heat from the south to ripen the fruit of the garden', 'a', 'Song of Solomon 4:16 — "Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out."'),
('Song of Solomon', 4, 'teens', 5, 'What does the beloved call the woman in chapter 4 — a title showing how precious she is to him?', 'My sister, my spouse', 'My dove, my undefiled', 'My fair one, my lily', 'My beloved, my queen', 'a', 'Song of Solomon 4:9 — "Thou hast ravished my heart, my sister, my spouse; thou hast ravished my heart with one of thine eyes, with one chain of thy neck."'),
-- Adults
('Song of Solomon', 4, 'adults', 1, 'What is a wasf, and how does Song of Solomon 4:1-7 exemplify this ancient Near Eastern literary form?', 'A wasf is an Arabic term for a poem that describes a person''s beauty from head to foot (or foot to head) through a series of comparisons; Song 4:1-7 follows this structure praising eyes, hair, teeth, lips, temples, neck, and breasts through seven consecutive images', 'A wasf is a betrothal contract read aloud before witnesses, and Song 4 records Solomon''s formal pledge to the woman', 'A wasf is a funeral lament repurposed for wedding celebrations, explaining the book''s mixture of joy and longing', 'A wasf is a Canaanite agricultural chant adapted for the wedding feast', 'a', 'Song of Solomon 4:1-7 moves systematically through physical features: eyes (v.1), hair (v.1), teeth (v.2), lips (v.3), temples (v.3), neck (v.4), breasts (v.5) — a head-to-chest wasf whose parallel has been found in Egyptian and Arabic love poetry, validating the book''s place in ancient Near Eastern literary culture while using distinctively Israelite landscapes for its images.'),
('Song of Solomon', 4, 'adults', 2, 'What is the theological and relational significance of the beloved calling the woman "my sister, my spouse" (Song of Solomon 4:9-10, 12)?', 'Sister-language in ancient Near Eastern marriage expresses the deepest personal intimacy and equal standing — she is simultaneously his closest family and his covenant partner, a combination expressing both affection and covenantal permanence', 'The sister title means she is literally his relative and the marriage is an endogamous family union', 'It is a term of endearment without specific covenantal or relational content', 'The sister language was borrowed from Egyptian love poetry and has no Hebraic theological weight', 'a', 'Song of Solomon 4:9 — "Thou hast ravished my heart, my sister, my spouse." In Egyptian love poetry "sister" was the standard term for a beloved woman, but in the Hebrew context it combines the absolute intimacy of family (sister) with the legal bond of covenant (spouse/bride, kallah), presenting ideal love as encompassing both dimensions.'),
('Song of Solomon', 4, 'adults', 3, 'How does the enclosed garden and sealed fountain imagery in Song of Solomon 4:12 function in the book''s theology of sexuality?', 'The imagery presents the woman''s sexuality as a protected space that is not publicly accessible — the sealing signifies purity and exclusive devotion rather than prohibition, with the beloved''s invitation in verse 16 opening what was sealed', 'The enclosed garden means she is imprisoned in the royal harem and cannot leave', 'The sealed fountain indicates she had taken a vow of celibacy that required special release', 'The garden enclosure is an architectural description of the temple gardens in Jerusalem', 'a', 'Song of Solomon 4:12 — "A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed." Song of Solomon 4:16 — "Let my beloved come into his garden." The garden is sealed not as a punishment but as a treasure — it is precious precisely because it is not open to all. The invitation of verse 16 is the woman herself unlocking what had been sealed, presenting her gift as freely given within covenant love.'),
('Song of Solomon', 4, 'adults', 4, 'What does the beloved''s description of the woman''s neck as "the tower of David builded for an armoury" (Song of Solomon 4:4) communicate?', 'The tower of David was a military stronghold decorated with weapons; the comparison praises the woman''s neck as noble, impressive, and adorned — possibly with jewellery — evoking strength and majesty rather than fragility', 'It is a negative comparison suggesting her neck is too long and stiff', 'The tower imagery is messianic and refers to the daughter of Zion rather than the literal woman', 'It compares her neck to ivory, since the tower of David was built of white stone', 'a', 'Song of Solomon 4:4 — "Thy neck is like the tower of David builded for an armoury, whereon there hang a thousand bucklers, all shields of mighty men." The tower is adorned with trophies of war — shields and bucklers — making it magnificent and impressive. The comparison praises her neck as stately and adorned, evoking majesty.'),
('Song of Solomon', 4, 'adults', 5, 'How does the catalogue of spices and rare plants in Song of Solomon 4:13-14 function in the garden metaphor, and what does the variety communicate?', 'The lavish list of rare imported spices (spikenard, saffron, calamus, cinnamon, frankincense, myrrh, aloes) presents the woman as a garden that contains the most precious things the known world has to offer — no single treasure exhausts her', 'The spice catalogue is a commercial inventory listing the products of the royal palace gardens', 'The spices are all associated with temple worship, identifying the woman as a sacred space parallel to the tabernacle', 'The list is borrowed from an Egyptian medical text and has no poetic function', 'a', 'Song of Solomon 4:13-14 — "Thy plants are an orchard of pomegranates...spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices." The rhetorical reach — "with all the chief spices" — suggests the catalogue itself cannot contain the totality of what she is.'),
('Song of Solomon', 4, 'adults', 6, 'What does the beloved''s invitation for the winds to blow so "that the spices thereof may flow out" (Song of Solomon 4:16) suggest about the nature of the love being described?', 'The winds carrying the garden''s fragrance outward suggest that this love, while intimate and enclosed, is meant to overflow — its beauty and goodness are not hoarded but released and shared, blessing all who encounter it', 'The wind invitation is a prayer for rain to water the literal garden of spices', 'It indicates the woman is inviting the beloved to leave so she can attend to her garden', 'The wind imagery represents the Holy Spirit and gives the verse a pneumatological meaning', 'a', 'Song of Solomon 4:16 — "Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out. Let my beloved come into his garden, and eat his pleasant fruits." The garden''s enclosed treasure is not meant to remain locked; the spices are meant to flow out — love''s intimacy is also generative and overflowing.'),
('Song of Solomon', 4, 'adults', 7, 'How does Song of Solomon 4:8 — "Come with me from Lebanon, my spouse, from Lebanon: look from the top of Amana, from the top of Shenir and Hermon, from the lions'' dens, from the mountains of the leopards" — function dramatically?', 'It presents the beloved issuing a dramatic summons from dangerous heights and wild terrain, casting the woman''s journey to him as a brave descent from peril into safety and love — her coming to him is itself a courageous act', 'It is a geographical description of where the woman was living before Solomon brought her to Jerusalem', 'It shows Solomon was conducting military campaigns in Lebanon while sending love messages', 'The wild animals indicate the verse belongs to a different poem about a shepherd and were inserted by mistake', 'a', 'Song of Solomon 4:8 — "Come with me from Lebanon, my spouse...from the lions'' dens, from the mountains of the leopards." The heights of Amana, Shenir, and Hermon are northern snow-capped mountains; lions and leopards evoke genuine danger. The invitation asks her to leave a beautiful but perilous place to come into the safety of his love.'),
('Song of Solomon', 4, 'adults', 8, 'How does the beloved''s declaration in Song of Solomon 4:7 — "There is no spot in thee" — function in both the human and allegorical dimensions of the text?', 'Literally it is a declaration of the woman''s perfect loveliness in his eyes; allegorically (reading the bride as Israel or the Church) it anticipates the New Testament language of presenting the Church "without spot or wrinkle" (Ephesians 5:27), grounding the eschatological vision in the language of covenantal love', 'It means she had no blemish that would legally disqualify her from marriage under Mosaic law', 'It is a hyperbole that the original audience would have recognised as poetic exaggeration without theological significance', 'The declaration is the woman''s own statement about herself, not the beloved''s', 'a', 'Song of Solomon 4:7 — "Thou art all fair, my love; there is no spot in thee." Ephesians 5:27 — "That he might present it to himself a glorious church, not having spot, or wrinkle, or any such thing; but that it should be holy and without blemish." The echo is deliberate: Paul''s vision of the Bride of Christ is clothed in the language of the Song.');

-- ═══ Song of Solomon Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Song of Solomon', 5, 'kids', 1, 'What does the woman say the beloved''s head is like in chapter 5?', 'The most fine gold', 'Purest silver', 'White alabaster', 'Ivory and cedar', 'a', 'Song of Solomon 5:11 — "His head is as the most fine gold, his locks are bushy, and black as a raven."'),
('Song of Solomon', 5, 'kids', 2, 'When the beloved knocked on her door at night, what did the woman do at first?', 'She hesitated and did not immediately open the door', 'She ran straight to the door and opened it quickly', 'She called out that she was asleep and could not come', 'She sent a servant to see who was there', 'a', 'Song of Solomon 5:3 — "I have put off my coat; how shall I put it on? I have washed my feet; how shall I defile them?" She gave excuses before rising to open the door.'),
('Song of Solomon', 5, 'kids', 3, 'What did the woman find when she finally rose to open the door for her beloved?', 'He had withdrawn himself and was gone', 'He was waiting outside with flowers for her', 'He had left a message with the watchmen', 'He stood at the gate of the city for her', 'a', 'Song of Solomon 5:6 — "I opened to my beloved; but my beloved had withdrawn himself, and was gone."'),
-- Teens
('Song of Solomon', 5, 'teens', 1, 'What happened to the woman when the watchmen of the city found her searching for her beloved in the night?', 'The watchmen smote her and wounded her and the keepers of the walls took away her veil', 'The watchmen told her to go home and would not help her search', 'The watchmen escorted her safely to Solomon''s palace', 'The watchmen asked her to describe the beloved and then helped her find him', 'a', 'Song of Solomon 5:7 — "The watchmen that went about the city found me, they smote me, they wounded me; the keepers of the walls took away my veil from me."'),
('Song of Solomon', 5, 'teens', 2, 'What does the woman tell the daughters of Jerusalem to say if they find her beloved?', 'That she is sick of love', 'That she has sought him since early morning', 'That his mother is looking for him', 'That the king''s banquet awaits him', 'a', 'Song of Solomon 5:8 — "I charge you, O daughters of Jerusalem, if ye find my beloved, that ye tell him, that I am sick of love."'),
('Song of Solomon', 5, 'teens', 3, 'What does the woman say about the beloved''s cheeks?', 'As a bed of spices, as sweet flowers', 'Like smooth alabaster filled with perfume', 'As rosewood polished by the craftsman', 'Like honey from the comb dripping sweetness', 'a', 'Song of Solomon 5:13 — "His cheeks are as a bed of spices, as sweet flowers: his lips like lilies, dropping sweet smelling myrrh."'),
('Song of Solomon', 5, 'teens', 4, 'What colour does the woman say the beloved''s eyes are like, and what are they washed with?', 'Like doves beside the rivers of waters, washed with milk and fitly set', 'Like sapphires set in silver beside still waters', 'Like dark pools reflecting the clear morning sky', 'Like the deep blue of the sea washed with sea-foam', 'a', 'Song of Solomon 5:12 — "His eyes are as the eyes of doves by the rivers of waters, washed with milk, and fitly set."'),
('Song of Solomon', 5, 'teens', 5, 'How does the woman conclude her description of her beloved to the daughters of Jerusalem?', 'He is altogether lovely and this is my beloved, this is my friend, O daughters of Jerusalem', 'He is the chiefest among ten thousand and there is none like him in all the earth', 'He is a king among men and I am his beloved forever', 'He is fairer than any man and his love is stronger than death', 'a', 'Song of Solomon 5:16 — "His mouth is most sweet: yea, he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem."'),
-- Adults
('Song of Solomon', 5, 'adults', 1, 'What is the significance of the beloved putting his hand "by the hole of the door" and the woman''s bowels moving (Song of Solomon 5:4) in the context of Hebrew physiology and the poem''s meaning?', 'In Hebrew anthropology the bowels (me''im) were the seat of tender emotion and compassion; the physical movement of longing (her inmost self was stirred) triggered by just his hand at the door shows love as a response of the whole person', 'It is a literal description of the woman feeling afraid when she heard someone at the door', 'The phrase is a euphemism indicating the consummation of the marriage', 'It describes the woman''s physical reaction to being woken from sleep', 'a', 'Song of Solomon 5:4 — "My beloved put in his hand by the hole of the door, and my bowels were moved for him." The Hebrew me''im (bowels, inward parts) appears in Genesis 43:30 for Joseph''s compassion and in 1 Kings 3:26 for a mother''s love — always indicating deep, involuntary emotional response from the innermost person.'),
('Song of Solomon', 5, 'adults', 2, 'What does the woman''s delay in opening the door (Song of Solomon 5:3) — and the consequent loss of the beloved — teach about the nature of love according to the poem?', 'Love requires immediacy and full response; hesitation born of self-comfort (I have washed my feet, put off my coat) leads to loss — the poem presents this as a moral and relational warning against the slow heart', 'The delay is presented approvingly as prudent modesty before opening to an unannounced visitor', 'It is a dream sequence and the lost beloved represents the woman''s unconscious anxiety, not a moral failure', 'The delay proves the woman did not truly love him, explaining why the relationship struggles in later chapters', 'a', 'Song of Solomon 5:3 — "I have put off my coat; how shall I put it on?" The excuses are trivial set against his call; her delay costs her his presence (v.6). The scene is structurally a fall narrative within the love story — not a fall from God but from full responsiveness to love''s call — and it drives the anguished search of verses 6-8.'),
('Song of Solomon', 5, 'adults', 3, 'The woman''s description of the beloved in Song of Solomon 5:10-16 is described by scholars as a reversed wasf (head to feet). What is the rhetorical effect of beginning with the head?', 'Beginning with the head (finest gold) and descending moves from the seat of intellect and authority downward through the body, presenting the beloved as noble and kingly from crown to foot, unlike the ascending wasf of chapter 4 which builds toward the face', 'The head-first order follows the order of judicial examination in Israelite law courts', 'The reversed wasf is a sign of mourning and the woman describes him this way because she believes he is dead', 'The head-first order is coincidental and reflects no deliberate structural choice', 'a', 'Song of Solomon 5:11-16 — "His head is as the most fine gold" (v.11), descending through locks, eyes, cheeks, lips, hands, belly, legs, countenance to "altogether lovely" (v.16). This contrasts with chapter 4''s wasf which ascended. Beginning with gold at the head presents him from his highest point of honour first.'),
('Song of Solomon', 5, 'adults', 4, 'What does the woman''s description of the beloved as "the chiefest among ten thousand" (Song of Solomon 5:10) contribute to the book''s portrayal of exclusive love?', 'The phrase dagul merevavah literally means distinguished/bannered from ten thousand — he stands out above all others; exclusive love sees the beloved as incomparable, not by belittling others but by the sheer surplus of devotion', 'It is a military census figure indicating Solomon commanded ten thousand soldiers', 'It borrows the language of the tribal muster in Numbers to place the beloved in a Mosaic context', 'The number ten thousand simply means a large but unspecified crowd', 'a', 'Song of Solomon 5:10 — "My beloved is white and ruddy, the chiefest among ten thousand." Dagul (chiefest) shares the root of degel (banner, standard), so "bannered above ten thousand" — he is the standard-bearer, the one who stands out above the whole assembly. This is love''s natural perception of the beloved.'),
('Song of Solomon', 5, 'adults', 5, 'What does the woman''s title for the beloved — "this is my beloved, and this is my friend" (Song of Solomon 5:16) — add to the book''s understanding of love?', 'It integrates two dimensions of relationship — passionate love (beloved/dodi) and deep companionship (friend/rea) — presenting complete love as requiring both eros and philia, desire and friendship', 'The title friend was a formal honorific used for members of the royal court', 'She calls him her friend to reassure the daughters of Jerusalem that the relationship is platonic', 'The two titles (beloved and friend) mark a transition in the book from romance to marriage', 'a', 'Song of Solomon 5:16 — "This is my beloved, and this is my friend, O daughters of Jerusalem." The word rea (friend) used here is the same root as the word used throughout the book for the woman herself (ra''yati — my friend/companion, Song 1:9, 2:2, etc.), suggesting a beautiful mutuality: she is his companion, and he is her friend.'),
('Song of Solomon', 5, 'adults', 6, 'How does the myrrh imagery run through Song of Solomon 5 (verses 1, 5, 13) and what cumulative effect does it create?', 'Myrrh appears in Solomon entering his garden and eating (v.1), on the woman''s hands at the door (v.5), and in the beloved''s lips (v.13); the spice of sacrifice and anointing permeates the chapter, associating love''s sweetest and costliest moments with the same substance', 'Myrrh appears only once in chapter 5 and is a generic spice with no cumulative significance', 'The myrrh imagery is borrowed from temple ritual to frame the chapter as a liturgical text', 'The repetition of myrrh is a scribal convention indicating that multiple poets contributed to the chapter', 'a', 'Song of Solomon 5:1 — "I have gathered my myrrh with my spice"; 5:5 — "My hands dropped with myrrh, and my fingers with sweet smelling myrrh upon the handles of the lock"; 5:13 — "his lips like lilies, dropping sweet smelling myrrh." Myrrh (mor) was both an anointing and an embalming spice — precious, costly, associated with consecration and sacrifice; its threefold presence in chapter 5 gives love both sweetness and gravity.'),
('Song of Solomon', 5, 'adults', 7, 'What does the daughters of Jerusalem''s question "What is thy beloved more than another beloved?" (Song of Solomon 5:9) accomplish in the poem''s structure?', 'It functions as a literary device prompting the woman''s wasf description of the beloved (verses 10-16) — the community''s challenge draws out the fullest declaration of love in the book and transforms private devotion into public testimony', 'It is a hostile question from rivals questioning the relationship', 'It invites the woman to compare Solomon to other suitors she has rejected', 'It is a rhetorical question that the poem treats as unanswerable without any response', 'a', 'Song of Solomon 5:9 — "What is thy beloved more than another beloved, O thou fairest among women?" This challenge from the daughters of Jerusalem is answered by the most detailed description of the beloved in the entire book (vv.10-16). The communal question becomes the occasion for the most complete personal testimony of love.'),
('Song of Solomon', 5, 'adults', 8, 'How does the wounding of the woman by the watchmen (Song of Solomon 5:7) parallel and contrast with the watchmen''s role in chapter 3, and what does the escalation reveal?', 'In chapter 3 the watchmen find her and she asks them a question but they do not harm her; in chapter 5 the same watchmen beat and wound her. The escalation shows that the deeper the love, the higher the cost of seeking it — vulnerability and suffering become part of the journey', 'The watchmen in chapter 5 are different men; the violence is coincidental and not a literary escalation', 'The chapter 5 scene is a dream and therefore the violence has no narrative consequence', 'The watchmen attacked her because she was violating the city curfew — a legal penalty, not a literary theme', 'a', 'Song of Solomon 3:3 — "The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?" No harm. Song of Solomon 5:7 — "The watchmen...found me, they smote me, they wounded me; the keepers of the walls took away my veil from me." The same institutional guardians cause injury the second time. As Bernard of Clairvaux observed, the soul that presses further into love encounters greater cost.');

-- ═══ Song of Solomon Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Song of Solomon', 6, 'kids', 1, 'When the daughters of Jerusalem ask where the beloved has gone, where does the woman say he is?', 'Gone down into his garden to the beds of spices, to feed in the gardens and gather lilies', 'He went up to the mountains of Lebanon for the harvest', 'He returned to the palace of the king for a royal feast', 'He is in the vineyards of Sharon gathering grapes', 'a', 'Song of Solomon 6:2 — "My beloved is gone down into his garden, to the beds of spices, to feed in the gardens, and to gather lilies."'),
('Song of Solomon', 6, 'kids', 2, 'What does the woman say again about herself and her beloved in chapter 6 using possessive language?', 'I am my beloved''s, and my beloved is mine: he feedeth among the lilies', 'My beloved belongs to me and I shall not let him go', 'We are bound together in love and nothing can part us', 'He is mine and I am his from the rising of the sun', 'a', 'Song of Solomon 6:3 — "I am my beloved''s, and my beloved is mine: he feedeth among the lilies."'),
('Song of Solomon', 6, 'kids', 3, 'What is the name the beloved calls the woman in chapter 6 that has become famous?', 'The Shulamite', 'The daughter of Zion', 'The rose of Sharon', 'The dove of Lebanon', 'a', 'Song of Solomon 6:13 — "Return, return, O Shulamite; return, return, that we may look upon thee."'),
-- Teens
('Song of Solomon', 6, 'teens', 1, 'The beloved says the woman is as terrible or awesome as what?', 'An army with banners', 'Thunder from the mountains', 'A storm upon the great sea', 'A lioness among her young', 'a', 'Song of Solomon 6:10 — "Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?"'),
('Song of Solomon', 6, 'teens', 2, 'What three celestial bodies does the beloved use to describe the woman''s appearance in chapter 6?', 'The morning, the moon, and the sun', 'The dawn, the stars, and the sun', 'The evening star, the moon, and the horizon', 'The sunrise, the noon sun, and the harvest moon', 'a', 'Song of Solomon 6:10 — "Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?"'),
('Song of Solomon', 6, 'teens', 3, 'What does the beloved say there are sixty queens, fourscore concubines, and virgins without number, but who is special above them all?', 'My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her', 'My beloved is the fairest of them all and the queens themselves praise her', 'Of all the daughters of the kingdom none compares to my beloved', 'She alone is my portion and my delight above all the women of the earth', 'a', 'Song of Solomon 6:8-9 — "There are threescore queens, and fourscore concubines, and virgins without number. My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her."'),
('Song of Solomon', 6, 'teens', 4, 'Where did the beloved go down before he found the woman in chapter 6?', 'Into the garden of nuts to see the fruits of the valley', 'To the vineyards of Engedi to gather spices', 'Down to the pools of Solomon to water the gardens', 'Into the valley of Kidron to find the lilies of the field', 'a', 'Song of Solomon 6:11 — "I went down into the garden of nuts to see the fruits of the valley, and to see whether the vine flourished, and the pomegranates budded."'),
('Song of Solomon', 6, 'teens', 5, 'What does the beloved repeat four times when he calls the Shulamite in Song of Solomon 6:13?', 'Return, return, O Shulamite; return, return', 'Come, come, O my love; come, come away', 'Rise, rise, my beloved; rise, rise and come', 'Stay, stay, O Shulamite; stay, stay with me', 'a', 'Song of Solomon 6:13 — "Return, return, O Shulamite; return, return, that we may look upon thee."'),
-- Adults
('Song of Solomon', 6, 'adults', 1, 'How does the mutual possession formula in Song of Solomon 6:3 — "I am my beloved''s, and my beloved is mine" — differ from its first occurrence in Song of Solomon 2:16 — "My beloved is mine, and I am his"?', 'In 2:16 her possession of him comes first (my beloved is mine), while in 6:3 her belonging to him comes first (I am my beloved''s) — a subtle but significant inversion showing a deepening of selflessness in the relationship over the course of the book', 'The two formulae are identical and the order carries no meaningful difference', 'The inversion indicates the chapter was written by a different author with a different theological emphasis', 'The order change reflects the legal transfer of property rights after the formal wedding of chapter 3', 'a', 'Song of Solomon 2:16 — "My beloved is mine, and I am his." Song of Solomon 6:3 — "I am my beloved''s, and my beloved is mine." The progression culminates in Song of Solomon 7:10 — "I am my beloved''s, and his desire is toward me" — where she drops the reciprocal clause entirely, showing complete gift of self.'),
('Song of Solomon', 6, 'adults', 2, 'What is the identity and significance of the "Shulamite" (Song of Solomon 6:13), and how has the name been interpreted?', 'Shulamite (Shulamit) is the feminine form of Solomon (Shelomoh), both deriving from shalom (peace) — the woman and the man may be seen as complementary embodiments of wholeness/peace; alternatively she is from Shunem (1 Kings 1:3)', 'The Shulamite is explicitly identified as the daughter of Pharaoh in the historical context', 'Shulamite means dark-skinned one in Hebrew and refers back to her complexion described in chapter 1', 'The name is entirely symbolic and refers to the city of Jerusalem (Shalem/Shalom)', 'a', 'Song of Solomon 6:13 — "Return, return, O Shulamite." The name occurs only here in the Bible. It is most plausibly the gentilic of Shunem (cf. 1 Kings 1:3, Abishag the Shunammite) or the feminine of Solomon, from the root shalom (peace), creating a wordplay where she and he are the feminine and masculine poles of wholeness.'),
('Song of Solomon', 6, 'adults', 3, 'What does the description of the woman as "terrible as an army with banners" (Song of Solomon 6:10) contribute to the book''s portrait of love''s power?', 'Love is not merely tender or passive — the woman''s beauty is also formidable and overwhelming, inspiring awe as much as desire. The military image suggests love''s power can be as arresting and decisive as a battle line bearing down on the observer', 'The army imagery is a negative comparison indicating the beloved fears the woman''s jealousy', 'It is a reference to the women''s procession at the festival of Shiloh described in Judges 21', 'The terror language is hyperbole that the original audience would not have taken seriously as a military reference', 'a', 'Song of Solomon 6:10 — "Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?" The fourfold comparison escalates from the gentle (morning) through the magnificent (sun) to the formidable (army). Love that is genuinely beautiful is also genuinely powerful — it can unmake a person.'),
('Song of Solomon', 6, 'adults', 4, 'Why does the beloved''s declaration that his dove is "but one" (Song of Solomon 6:8-9), set against sixty queens and eighty concubines, carry particular weight in the context of Solomon''s reign?', '1 Kings 11:3 records Solomon had 700 wives and 300 concubines; against that backdrop the declaration that she alone is the one speaks to the ideal of exclusive, undivided love that stands in contrast to the very proliferation that would prove Solomon''s undoing', 'The contrast is purely literary and has no connection to Solomon''s historical situation', 'The queens and concubines listed are the women of other courts, not Solomon''s own household', 'The number sixty is symbolic for completeness and the verse means she surpasses all women theoretically, not actually', 'a', 'Song of Solomon 6:8-9 — "There are threescore queens, and fourscore concubines...My dove, my undefiled is but one." 1 Kings 11:3 — "He had seven hundred wives...and three hundred concubines: and his wives turned away his heart." The Song holds up the ideal (one beloved) against the tragic reality of Solomon''s history, suggesting the book itself is a corrective vision.'),
('Song of Solomon', 6, 'adults', 5, 'What is the literary function of the daughters of Jerusalem''s praise of the woman in Song of Solomon 6:9 — "the queens and the concubines praised her"?', 'It functions as an objective, disinterested endorsement — the beloved''s praise could be dismissed as partiality, but when his rivals'' own women spontaneously praise her, her excellence is confirmed by the community', 'It is a courtesy formula used in ancient court poetry to honour the queen', 'The queens praise her because they pity her as an outsider brought into the court against her will', 'The praise is ironic and the daughters are actually jealous of her position', 'a', 'Song of Solomon 6:9 — "The daughters saw her, and blessed her; yea, the queens and the concubines, and they praised her." The testimonial from rivals and potential adversaries functions as the most reliable of endorsements — when those who have reason to be jealous cannot help but praise, the excellence is beyond dispute.'),
('Song of Solomon', 6, 'adults', 6, 'How does the garden of nuts episode (Song of Solomon 6:11-12) function in the narrative, and what does the woman''s sudden presence in the royal chariots suggest?', 'The episode shows love''s transformative power: she went down to see the garden and before she knew it (before she was aware) she was caught up in something greater than herself — love overwhelms the will and carries the beloved beyond ordinary expectations', 'The episode is a political allegory describing the woman''s elevation from rural poverty to court status', 'The chariot reference identifies the woman as a warrior princess from a royal family', 'The sudden transport is a dream element indicating the garden of nuts is a visionary space', 'a', 'Song of Solomon 6:11-12 — "I went down into the garden of nuts...Or ever I was aware, my soul made me like the chariots of Amminadib." The unexpected phrase "before I was aware" captures love''s overwhelming quality — it exceeds intention and rational control, lifting the beloved into a new register of experience.'),
('Song of Solomon', 6, 'adults', 7, 'How do the four-fold "return" calls in Song of Solomon 6:13 function both dramatically and theologically?', 'The fourfold call creates urgency and longing — the community desires to see her, suggesting her beauty and love are not merely private but have a public and communal magnetism that draws others toward what is beautiful and whole', 'The four calls are a liturgical chant structure modelled on the Aaronic blessing in Numbers 6', 'The repetition indicates she has actually left and is physically far away, requiring a long journey back', 'The fourfold return is a contractual formula requiring the woman to acknowledge the call four times', 'a', 'Song of Solomon 6:13 — "Return, return, O Shulamite; return, return, that we may look upon thee." The desire to look upon (chazah — perceive, behold) the Shulamite is not voyeuristic but contemplative — the community seeks to see and receive what love has produced in her. True love is not merely private; it makes the beloved beautiful before the world.'),
('Song of Solomon', 6, 'adults', 8, 'How does Song of Solomon chapter 6 resolve the crisis of chapter 5 (the beloved''s absence after the woman''s delay), and what does the resolution pattern teach about covenant love?', 'Chapter 6 opens with the woman knowing exactly where her beloved is (in the garden) despite having searched in vain in chapter 5 — the resolution comes not through frantic searching but through the return to the garden and the relationship''s own ground; covenant love finds its way back', 'Chapter 6 resolves the crisis by the beloved formally forgiving the woman for her delay in chapter 5', 'The crisis is not resolved in chapter 6 — the woman is still searching, and resolution only comes in chapter 8', 'The crisis was a dream in chapter 5 and chapter 6 confirms they were never separated', 'a', 'Song of Solomon 5:6 — "I sought him, but I found him not." Song of Solomon 6:2-3 — "My beloved is gone down into his garden...I am my beloved''s and my beloved is mine." Without any described search or dramatic encounter, chapter 6 opens with the woman knowing where he is and re-affirming mutual belonging. Covenant love returns to its own nature.');

-- ═══ Song of Solomon Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Song of Solomon', 7, 'kids', 1, 'What does the beloved compare the woman''s navel to in chapter 7?', 'A round goblet that wanteth not liquor', 'A bowl of honey from the comb', 'A golden cup full of spices', 'A basin carved from marble', 'a', 'Song of Solomon 7:2 — "Thy navel is like a round goblet, which wanteth not liquor: thy belly is like an heap of wheat set about with lilies."'),
('Song of Solomon', 7, 'kids', 2, 'What does the beloved compare the woman''s neck to in chapter 7?', 'A tower of ivory', 'The tower of David', 'A pillar of cedar', 'A column of silver', 'a', 'Song of Solomon 7:4 — "Thy neck is as a tower of ivory."'),
('Song of Solomon', 7, 'kids', 3, 'What does the woman invite her beloved to do with her at the end of chapter 7?', 'Come, my beloved, let us go forth into the field and lodge in the villages', 'Let us climb to the top of the mountains and look over the land', 'Let us return to my mother''s house and rest together', 'Let us rise early and go down to the vineyard of the king', 'a', 'Song of Solomon 7:11 — "Come, my beloved, let us go forth into the field; let us lodge in the villages."'),
-- Teens
('Song of Solomon', 7, 'teens', 1, 'What does the woman say about who her beloved''s desire is toward?', 'His desire is toward me', 'His desire is toward the daughters of Zion', 'His desire is for righteousness and love', 'His desire is for peace and joy in the vineyard', 'a', 'Song of Solomon 7:10 — "I am my beloved''s, and his desire is toward me."'),
('Song of Solomon', 7, 'teens', 2, 'What does the beloved say the woman''s stature is like and that her breasts are like?', 'Thy stature is like to a palm tree and thy breasts like clusters of grapes', 'Thy stature is like a cedar and thy breasts like pomegranates', 'Thy stature is like the temple column and thy breasts like lilies of the valley', 'Thy stature is like a young vine and thy breasts like clusters of henna', 'a', 'Song of Solomon 7:7-8 — "This thy stature is like to a palm tree, and thy breasts to clusters of grapes."'),
('Song of Solomon', 7, 'teens', 3, 'What does the woman say she will give to her beloved when they go to the vineyards in the early morning?', 'There will I give thee my loves', 'There I will sing thee the songs of thy people', 'There we shall eat the firstfruits together', 'There I will crown thee with a garland of spices', 'a', 'Song of Solomon 7:12 — "Let us get up early to the vineyards; let us see if the vine flourish, whether the tender grape appear, and the pomegranates bud forth: there will I give thee my loves."'),
('Song of Solomon', 7, 'teens', 4, 'What delicacy does the woman say she has laid up at the doors for her beloved?', 'All manner of pleasant fruits, new and old', 'The first grapes of the vintage and fresh pomegranates', 'Cakes of figs and jars of honey from the comb', 'Bread of the firstfruits and spiced wine', 'a', 'Song of Solomon 7:13 — "At our gates are all manner of pleasant fruits, new and old, which I have laid up for thee, O my beloved."'),
('Song of Solomon', 7, 'teens', 5, 'What does the beloved say are like clusters of the vine and like the smell of apples?', 'The woman''s breasts', 'Her lips and her tongue', 'The fragrance of her garments', 'Her hands and her feet', 'a', 'Song of Solomon 7:8 — "Thy breasts shall be as clusters of the vine, and the smell of thy nose like apples."'),
-- Adults
('Song of Solomon', 7, 'adults', 1, 'How does Song of Solomon 7:10 — "I am my beloved''s, and his desire is toward me" — mark the culmination of the three mutual possession formulae in the book (2:16, 6:3, 7:10)?', 'The progression moves from claiming him (my beloved is mine, 2:16) to belonging to him first (I am my beloved''s, 6:3) to complete self-gift with the addition of his desire toward her (7:10) — each stage deepens self-surrender while gaining assurance of being fully desired', 'The three formulae are equivalent statements of the same truth and show no progression', 'The formula in 7:10 is spoken by the beloved rather than the woman, reversing the earlier pattern', 'The change from mutual to unilateral possession in 7:10 indicates a decline in the relationship''s health', 'a', 'Song of Solomon 2:16 — "My beloved is mine, and I am his." Song of Solomon 6:3 — "I am my beloved''s, and my beloved is mine." Song of Solomon 7:10 — "I am my beloved''s, and his desire is toward me." The arc moves from possession (mine) to belonging (his) to the discovery of being desired — the highest gift.'),
('Song of Solomon', 7, 'adults', 2, 'What is the theological resonance of "his desire is toward me" (Song of Solomon 7:10) given the use of the same word (teshuqah — desire) in Genesis 3:16?', 'Genesis 3:16 uses teshuqah to describe the woman''s distorted desire for her husband under the curse; Song of Solomon 7:10 inverts this — the man''s desire is now described with the same word, suggesting the garden of love in the Song restores what was broken at the Fall', 'The word teshuqah is common Hebrew with no deliberate Genesis connection in Song 7:10', 'Genesis 3:16 describes God''s desire for humanity, not the man''s desire for the woman', 'The connection to Genesis 3:16 is a later allegorical reading not intended by the original poem', 'a', 'Genesis 3:16 — "thy desire (teshuqah) shall be to thy husband, and he shall rule over thee." This is the curse: disordered desire and domination. Song of Solomon 7:10 — "his desire (teshuqah) is toward me." The same word now describes the man''s desire turned fully toward the woman — the poem envisions love as the reversal of the curse, a restored Edenic relationship.'),
('Song of Solomon', 7, 'adults', 3, 'How does the beloved''s third wasf in Song of Solomon 7:1-9 differ from the wasf in chapters 4-5 in terms of direction and tone?', 'Chapter 7''s wasf begins at the feet (how beautiful are thy feet with shoes) and ascends to the head — an upward movement that mirrors the woman''s own growing confidence and full presence, culminating in the beloved''s desire to climb the palm tree and take hold of its branches', 'All three wasfs in the book follow the same head-to-foot direction and show no structural difference', 'Chapter 7''s wasf begins at the head rather than the feet, making it structurally identical to chapter 4', 'The direction of the wasf in chapter 7 is indeterminate since the body parts are listed randomly', 'a', 'Song of Solomon 7:1 — "How beautiful are thy feet with shoes, O prince''s daughter!" The wasf begins at the feet and ascends: feet (v.1), thighs (v.1), navel (v.2), belly (v.2), breasts (v.3-8), neck (v.4), eyes (v.4), nose (v.4), head (v.5), hair (v.5). This ascending movement to the head mirrors the beloved''s declaration in verse 8 that he will go up to the palm tree.'),
('Song of Solomon', 7, 'adults', 4, 'What does calling the woman "prince''s daughter" (bat-nadib, Song of Solomon 7:1) contribute to her characterisation throughout the book?', 'It elevates her status from the sun-darkened vineyard keeper of chapter 1 to noble daughter — whether literally or metaphorically, love itself has made her royal, tracing a transformation across the book from social outsider to recognised nobility', 'It identifies her as the daughter of a foreign king whom Solomon married for political reasons', 'The title is a generic honorific applied to all women in royal court poetry without specific meaning', 'It shows that by chapter 7 her identity has been legally changed through the marriage ceremony of chapter 3', 'a', 'Song of Solomon 7:1 — "How beautiful are thy feet with shoes, O prince''s daughter!" Compare Song of Solomon 1:5-6 where she is a tanned vineyard keeper looked down upon. The trajectory from social outsider to bat-nadib (noble daughter/daughter of a prince) enacted through love''s transformation is one of the book''s quiet themes.'),
('Song of Solomon', 7, 'adults', 5, 'What is the significance of the woman taking the initiative to invite the beloved to the countryside in Song of Solomon 7:11-13?', 'The woman''s active invitation reverses the usual pattern of the male initiating; her agency grows across the book and here she becomes the architect of their meeting — love matures into mutual, active pursuit rather than passive receptivity', 'It shows the woman had not yet been formally invited to the king''s palace and was suggesting an alternative meeting place', 'The woman''s initiative is presented as a violation of Israelite custom and the beloved declines in chapter 8', 'The rural invitation indicates the couple are unmarried and the vineyard is the only place they can meet', 'a', 'Song of Solomon 7:11-12 — "Come, my beloved, let us go forth into the field; let us lodge in the villages...there will I give thee my loves." She plans, she invites, she sets the location, and she promises her gift of love. Her growing agency is a thread across the book — from seeking him (ch.3) to being sought (ch.5) to now actively leading (ch.7).'),
('Song of Solomon', 7, 'adults', 6, 'How does the mandrake imagery in Song of Solomon 7:13 connect to earlier biblical usage, and what does it contribute to the chapter?', 'Mandrakes (dudaim) were fertility plants associated with love-making (Genesis 30:14-16 — Rachel and Leah''s bargain); their presence in the garden gives the invitation of verse 12 erotic and fertility overtones while rooting the lovers'' relationship in the creation mandate to be fruitful', 'Mandrakes are simply pleasant-smelling herbs with no specific biblical or sexual resonance', 'The mandrake reference is borrowed from Egyptian garden poetry and has no connection to the Genesis narrative', 'Mandrakes were used in temple incense and the reference places the garden visit in a cultic context', 'a', 'Song of Solomon 7:13 — "The mandrakes give a smell, and at our gates are all manner of pleasant fruits." Genesis 30:14-16 — Reuben found mandrakes (dudaim) in the field and Rachel bargained with Leah for them because of their fertility/love association. The same word dudaim echoes the word for beloved (dod), creating a pun that suffuses the garden invitation with erotic and generative meaning.'),
('Song of Solomon', 7, 'adults', 7, 'How does the beloved''s description of the woman''s walk — "How beautiful are thy feet with shoes, O prince''s daughter! The joints of thy thighs are like jewels" (Song of Solomon 7:1) — reflect the social setting of a dance?', 'The reference to sandals and the context of "return, return, O Shulamite" from the previous verse suggests a dance (the Mahanaim dance of 6:13) in which the woman''s movement, posture, and adorned feet are being admired by an audience', 'The verse describes the woman walking to the marketplace and her sandals are mentioned for realism', 'The sandal reference identifies her as a Levite since only Levites wore decorated sandals in Israel', 'The verse follows a wedding procession where the bride''s feet were formally blessed', 'a', 'Song of Solomon 6:13 — "What will ye see in the Shulamite? As it were the company of two armies (Mahanaim)." Song of Solomon 7:1 — "How beautiful are thy feet with shoes, O prince''s daughter!" Mahanaim means two camps and may describe a dance performance. The transition from the "look upon thee" of 6:13 to the admiration of her feet and movement in 7:1 places the wasf in the context of a dance being observed.'),
('Song of Solomon', 7, 'adults', 8, 'What does the whole of chapter 7''s movement — from a public dance setting (7:1) to an intimate private invitation (7:11-13) — reveal about the book''s theology of love''s seasons?', 'Love has both public and private dimensions: it can be celebrated openly and seen by the community (dance), yet its deepest gifts are reserved for private covenant space (the field and village). True love is neither purely private nor purely public but rhythmically moves between the two', 'Chapter 7 shows the relationship deteriorating from public honour to private secrecy', 'The movement from public to private marks the legal transition from betrothal to consummation', 'The shift is structural only — the public-to-private movement has no theological implication', 'a', 'Song of Solomon 7:1 — "How beautiful are thy feet with shoes" (public admiration in the dance). Song of Solomon 7:11-13 — "Come, my beloved, let us go forth into the field...there will I give thee my loves" (private invitation). The book throughout holds together love as both publicly honourable and privately intimate — neither reduced to performance nor hidden in shame.');

-- ═══ Song of Solomon Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Song of Solomon', 8, 'kids', 1, 'What does the woman ask to be placed upon the beloved''s heart, like a seal?', 'Set me as a seal upon thine heart', 'Put my ring upon thy finger as a token', 'Place my name upon thy garment', 'Keep my gift as a seal upon thy hand', 'a', 'Song of Solomon 8:6 — "Set me as a seal upon thine heart, as a seal upon thine arm."'),
('Song of Solomon', 8, 'kids', 2, 'What does the woman say cannot put out or quench love?', 'Many waters cannot quench love, neither can the floods drown it', 'No enemy can take it away from those who hold it fast', 'No distance of land or sea can separate those who love', 'Neither time nor sorrow can cause true love to fade', 'a', 'Song of Solomon 8:7 — "Many waters cannot quench love, neither can the floods drown it."'),
('Song of Solomon', 8, 'kids', 3, 'What does the woman say about her little sister who has no breasts yet?', 'We have a little sister, and she hath no breasts: what shall we do for our sister?', 'Our little sister is young and we must find her a husband among the princes', 'My little sister waits for me at the vineyard of our mother', 'My sister is young but she is lovely and will be beautiful in her time', 'a', 'Song of Solomon 8:8 — "We have a little sister, and she hath no breasts: what shall we do for our sister in the day when she shall be spoken for?"'),
-- Teens
('Song of Solomon', 8, 'teens', 1, 'What does the woman say love is as strong as?', 'Death, and jealousy is cruel as the grave', 'The mountains of Lebanon that cannot be moved', 'The sun whose heat none can escape', 'The sea whose waters fill all the earth', 'a', 'Song of Solomon 8:6 — "Love is strong as death; jealousy is cruel as the grave."'),
('Song of Solomon', 8, 'teens', 2, 'What does the woman say her vineyard, which is hers, is worth compared to Solomon''s great vineyard at Baal-hamon?', 'Thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred. My vineyard, which is mine, is before me', 'My vineyard is greater than Solomon''s because love tends it', 'Solomon has all the vineyards of Israel but I have what is mine', 'My vineyard yields more fruit than all the vineyards of the king', 'a', 'Song of Solomon 8:11-12 — "Solomon had a vineyard at Baal-hamon...My vineyard, which is mine, is before me: thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred."'),
('Song of Solomon', 8, 'teens', 3, 'What does the woman say she would do if she could meet her beloved in the street like a brother, and why does she wish this?', 'She would kiss him and not be despised, and would bring him to her mother''s house', 'She would take him to the gate and declare her love before all the elders', 'She would give him wine from her vineyard and break bread with him openly', 'She would lead him to the king''s house and present him to her family', 'a', 'Song of Solomon 8:1-2 — "O that thou wert as my brother...I would kiss thee; yea, I should not be despised. I would lead thee, and bring thee into my mother''s house."'),
('Song of Solomon', 8, 'teens', 4, 'What does the beloved say about the woman leaning upon him as she comes up from the wilderness?', 'Who is this that cometh up from the wilderness, leaning upon her beloved?', 'Behold, she comes like the dawn arising from the mountains', 'My beloved rises from the desert as one clothed in glory', 'I awakened her under the apple tree where her mother travailed', 'a', 'Song of Solomon 8:5 — "Who is this that cometh up from the wilderness, leaning upon her beloved?"'),
('Song of Solomon', 8, 'teens', 5, 'What does the woman say about anyone who tries to buy love with all the substance or wealth of his house?', 'It would utterly be contemned or scorned', 'It could never be enough to satisfy true love', 'Such a man is a fool and knows nothing of love', 'He has mistaken riches for what belongs only to the heart', 'a', 'Song of Solomon 8:7 — "If a man would give all the substance of his house for love, it would utterly be contemned."'),
-- Adults
('Song of Solomon', 8, 'adults', 1, 'What is the significance of the seal imagery in Song of Solomon 8:6 — "Set me as a seal upon thine heart, as a seal upon thine arm"?', 'In the ancient world a seal (hotam) was pressed into clay or wax to establish identity, ownership, and legal authority; to ask to be set as a seal upon the heart and arm is to ask to be the beloved''s defining mark — on the inmost self (heart) and in all outward action (arm)', 'The seal imagery is borrowed from legal contracts and has no particular relational or theological resonance', 'The seal refers to the signet ring of betrothal that was placed on the woman''s hand at the marriage ceremony', 'It is a military image: the seal on the arm was worn by soldiers entering battle', 'a', 'Song of Solomon 8:6 — "Set me as a seal upon thine heart, as a seal upon thine arm." Genesis 38:18 (Judah''s signet/hotam) and Haggai 2:23 ("I will make thee as a signet") use the same word for the seal of identity and authority. The request is to be permanently impressed into the beloved''s identity — not temporarily but definitively.'),
('Song of Solomon', 8, 'adults', 2, 'How does the declaration "love is strong as death" (Song of Solomon 8:6) function as the theological climax of the book, and what does the comparison reveal?', 'Death is the one absolute — universal, inevitable, and irresistible; by comparing love''s strength to death, the poem declares that love is equally absolute and irresistible. It is not that love defeats death here, but that love is its only rival in absolute power', 'The comparison is hyperbole intended only to praise the intensity of romantic feeling', 'It means love causes death — the jealousy described in the same verse is a warning against obsessive love', 'It is a statement about the love of God for Israel rather than human love between individuals', 'a', 'Song of Solomon 8:6 — "Love is strong as death; jealousy is cruel as the grave: the coals thereof are coals of fire, which hath a most vehement flame." The Hebrew sheol (grave/realm of death) was understood as the great equaliser, claiming all. To say love is its equal is to say love is among the absolute realities — which is why Paul echoes this in Romans 8:38-39 and John 3:16 grounds the gospel in the same logic.'),
('Song of Solomon', 8, 'adults', 3, 'What is the meaning of "the coals thereof are coals of fire, which hath a most vehement flame" (Song of Solomon 8:6), and what does the Hebrew shalhevetyah contribute?', 'The Hebrew shalhevetyah (a most vehement flame) may contain the divine name Yah (a shortened form of YHWH) — making this the book''s only possible explicit reference to God, suggesting love''s fiercest flame partakes of divine fire', 'Shalhevetyah is simply a superlative compound meaning the hottest possible flame without any divine name', 'The fire imagery is borrowed from the altar of burnt offering and presents love as a sacrifice', 'The compound word identifies the flame as the pillar of fire that led Israel in the wilderness', 'a', 'Song of Solomon 8:6 — "the coals thereof are coals of fire, which hath a most vehement flame (shalhevetyah)." Hebrew lexicographers including Gesenius note that shalhevetyah may be shalhebet + Yah (flame of the LORD), making this either the strongest superlative in the Hebrew language or an explicit claim that love''s ultimate fire is nothing less than divine. Either reading is theologically rich.'),
('Song of Solomon', 8, 'adults', 4, 'How does the statement "if a man would give all the substance of his house for love, it would utterly be contemned" (Song of Solomon 8:7) function as a theological declaration about love''s nature?', 'Love cannot be purchased because it belongs to a different order of reality than commercial exchange; it is given freely or not at all. Any attempt to buy it with wealth reveals a fundamental misunderstanding of what love is', 'It is a legal principle warning against selling a woman into marriage for a bride price', 'It means that wealthy men make poor lovers and the woman is warning Solomon against trying to impress her with gifts', 'The verse counsels financial prudence — do not spend your wealth pursuing love because it is unstable', 'a', 'Song of Solomon 8:7 — "Many waters cannot quench love, neither can the floods drown it: if a man would give all the substance of his house for love, it would utterly be contemned." The verse places love outside the economy of barter. Love is not a commodity. It cannot be destroyed by force (waters) nor acquired by wealth (substance). Its only medium is free, self-giving devotion.'),
('Song of Solomon', 8, 'adults', 5, 'How does the vineyard motif in Song of Solomon 8:11-12 bring the book''s vineyard imagery to a conclusion, and what does "my vineyard, which is mine, is before me" declare?', 'The book opens with the woman unable to keep her own vineyard (1:6); it closes with her asserting that her vineyard — herself — is fully and freely hers to give. The contrast traces the whole arc of the book from lost self-possession to recovered identity', 'The vineyard in chapter 8 is a literal farm that the couple has acquired through marriage', 'The contrast between Solomon''s vineyard and hers is purely financial, comparing the value of rural vs royal property', 'The woman''s vineyard in chapter 8 is the same vineyard she kept for her brothers in chapter 1, showing she has returned home', 'a', 'Song of Solomon 1:6 — "mine own vineyard have I not kept." Song of Solomon 8:12 — "My vineyard, which is mine, is before me." The inclusion (bookend) is deliberate: the woman who could not tend her own vineyard has, through the journey of love, come into full ownership of herself — her vineyard is now hers to give rather than taken from her.'),
('Song of Solomon', 8, 'adults', 6, 'What does the community''s question about the little sister (Song of Solomon 8:8-9) introduce, and how does the woman''s response in verse 10 reflect her own completed journey?', 'The community debates how to protect a girl not yet ready for love; the woman''s response — "I am a wall, and my breasts like towers: then was I in his eyes as one that found favour" — presents herself as the resolution: she became her own wall of integrity and was received with favour, offering the model for her sister', 'The little sister passage is a genealogical note identifying the woman''s family background', 'The community is discussing a property dispute about the sister''s inheritance rights', 'The woman''s response in verse 10 is unrelated to the sister question and addresses her beloved directly', 'a', 'Song of Solomon 8:8-9 — "We have a little sister...what shall we do for our sister?" Song of Solomon 8:10 — "I am a wall, and my breasts like towers: then was I in his eyes as one that found favour (shalom)." Her own formation — keeping herself as an enclosed garden until love''s proper time — is the answer she embodies. She did not remain a locked door (v.9) but a wall that chose to open in its own time.'),
('Song of Solomon', 8, 'adults', 7, 'How does the woman''s request in Song of Solomon 8:14 — "Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices" — echo the book''s opening and what does ending here reveal about love?', 'It echoes Song of Solomon 2:8-9 where the beloved first appeared leaping like a roe; ending the book with the same image suggests love''s desire is never fully exhausted — it ends in longing and invitation rather than arrival, depicting love as an ongoing pursuit rather than a completed possession', 'The verse shows the relationship has ended since the woman sends the beloved away to the mountains', 'The closing verse is a liturgical dismissal, ending the wedding ceremony described in the book', 'It indicates the woman has rejected the beloved and the book ends unresolved', 'a', 'Song of Solomon 2:8-9 — "Behold, he cometh leaping upon the mountains, skipping upon the hills. My beloved is like a roe or a young hart." Song of Solomon 8:14 — "Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices." The book closes not with satisfied possession but with renewed longing — an eschatological posture that the New Testament appropriates in Revelation 22:20: "Even so, come, Lord Jesus."'),
('Song of Solomon', 8, 'adults', 8, 'How does the whole book of Song of Solomon function canonically within the Hebrew Bible, and what does its position in the Writings (Ketuvim) alongside Psalms, Proverbs, and Ecclesiastes suggest about its purpose?', 'Positioned among the wisdom literature, the Song offers a theology of embodied, covenantal love as part of God''s created order — not a lesser or suspicious topic but wisdom''s own engagement with what it means to be fully human. It declares that faithful love between persons reflects something true about the nature of God and creation', 'The Song was placed in the Writings accidentally because it fit neither the Law nor the Prophets', 'Its canonical position indicates it is primarily historical, recording the actual relationship of Solomon with a named historical figure', 'The Song belongs to the Writings only because it was too controversial for the Law or Prophets', 'a', 'The Song''s placement in the Ketuvim alongside Proverbs (which ends with the eshet hayil of Proverbs 31, echoing Ruth 3:11 and Song 3:11) and Qohelet (Ecclesiastes, also Solomonic) creates a wisdom cluster exploring what it means to live well. Rabbi Akiva''s verdict — "the Song of Songs is the Holy of Holies" (Mishnah Yadaim 3:5) — understands the book not as erotic literature appended to Scripture but as wisdom''s holiest chamber: the place where love, creation, and the divine nature meet.');
